import React, { useState, useEffect, useRef } from 'react';
import './Projects.css';

const projects = [
  {
    title: 'Multi-Cloud Infrastructure Automation',
    desc: 'Automated provisioning of AWS and Azure infrastructure using Terraform and Ansible. Reduced deployment time by 70% and achieved 99.9% uptime SLA across environments.',
    tags: ['AWS', 'Azure', 'Terraform', 'Ansible', 'CI/CD'],
    icon: '☁️',
    links: { github: '#', live: '#' },
  },
  {
    title: 'Kubernetes CI/CD Pipeline',
    desc: 'Built end-to-end CI/CD pipelines with GitHub Actions, Docker, and Kubernetes. Implemented blue-green deployments with automated rollback on failure.',
    tags: ['Docker', 'Kubernetes', 'CI/CD', 'GitHub Actions'],
    icon: '⚙️',
    links: { github: '#', live: null },
  },
  {
    title: 'Cloud Cost Governance Dashboard',
    desc: 'Developed a real-time cost monitoring dashboard integrating AWS Cost Explorer and Azure Cost Management APIs, reducing cloud spend by 35%.',
    tags: ['AWS', 'Azure', 'React.js', 'Python'],
    icon: '📊',
    links: { github: '#', live: '#' },
  },
  {
    title: 'Zero-Downtime Database Migration',
    desc: 'Orchestrated migration of 500GB PostgreSQL database from on-premise to AWS RDS with CDC using AWS DMS, achieving zero data loss and <30s downtime.',
    tags: ['AWS', 'Docker', 'CI/CD'],
    icon: '🗄️',
    links: { github: '#', live: null },
  },
  {
    title: 'SRE Observability Stack',
    desc: 'Deployed full observability stack with Prometheus, Grafana, and Loki on Kubernetes. Created 50+ dashboards and automated alerting with PagerDuty integration.',
    tags: ['Docker', 'Kubernetes', 'Azure', 'CI/CD'],
    icon: '🔭',
    links: { github: '#', live: null },
  },
  {
    title: 'DevOps Portfolio Website',
    desc: 'Designed and built this portfolio using React.js with neumorphic design, CI/CD deployment on Vercel, and infrastructure as code for environment management.',
    tags: ['React.js', 'CI/CD', 'Docker'],
    icon: '🌐',
    links: { github: '#', live: '#' },
  },
];

const allTags = ['All', ...Array.from(new Set(projects.flatMap((p) => p.tags)))];

export default function Projects() {
  const [active, setActive] = useState('All');
  const [animKey, setAnimKey] = useState(0);
  const gridRef = useRef(null);

  const filtered = active === 'All' ? projects : projects.filter((p) => p.tags.includes(active));

  // Re-trigger card entrance animation on filter change
  const handleFilter = (tag) => {
    setActive(tag);
    setAnimKey((k) => k + 1);
  };

  // Re-run IntersectionObserver each time filter changes so cards animate in
  useEffect(() => {
    if (!gridRef.current) return;
    const cards = gridRef.current.querySelectorAll('.project-card');
    cards.forEach((card, i) => {
      card.style.opacity = '0';
      card.style.transform = 'translateY(24px)';
      setTimeout(() => {
        card.style.transition = 'opacity 0.35s ease, transform 0.35s ease';
        card.style.opacity = '1';
        card.style.transform = 'translateY(0)';
      }, i * 80);
    });
  }, [animKey, filtered.length]);

  return (
    <section id="projects">
      <div className="container">
        <div className="section-header">
          <span className="section-tag">04 // Projects</span>
          <h2 className="section-title">Featured Work</h2>
          <div className="section-line" />
        </div>

        <div className="project-filters">
          {allTags.map((tag) => (
            <button
              key={tag}
              className={`filter-btn${active === tag ? ' active' : ''}`}
              onClick={() => handleFilter(tag)}
            >
              {tag}
            </button>
          ))}
        </div>

        {filtered.length === 0 ? (
          <div className="no-projects">
            <span className="no-projects-icon">🔍</span>
            <p>No projects match this filter.</p>
          </div>
        ) : (
          <div className="projects-grid" ref={gridRef} key={animKey}>
            {filtered.map((p) => (
              <div className="project-card" key={p.title}>
                <div className="project-card-top">
                  <span className="project-icon">{p.icon}</span>
                  <div className="project-links">
                    {p.links.github && (
                      <a href={p.links.github} target="_blank" rel="noreferrer" title="GitHub">
                        <i className="fab fa-github" />
                      </a>
                    )}
                    {p.links.live && (
                      <a href={p.links.live} target="_blank" rel="noreferrer" title="Live Demo">
                        <i className="fas fa-external-link-alt" />
                      </a>
                    )}
                  </div>
                </div>
                <h3 className="project-title">{p.title}</h3>
                <p className="project-desc">{p.desc}</p>
                <div className="project-tags">
                  {p.tags.map((t) => (
                    <span key={t} className="project-tag">{t}</span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}
